def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = None
    for s_idx, s in enumerate(prs.slides, 1):
        if s_idx == 23:
            slide = s
            break
    if slide is None:
        return ("Slide 23 does not exist in the modified presentation.", 0.0)
    found = False
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue
        for paragraph in shape.text_frame.paragraphs:
            if 'Conclusion:' in paragraph.text:
                found = True
                break
        if found:
            break
    if found:
        return ("'Conclusion:' text is present on slide 23.", 1.0)
    else:
        return ("'Conclusion:' text is missing from slide 23.", 0.0)

def compute_score() -> tuple[str, float]:
    # Find slide 5 screenshot
    img = None
    for ss in modified_ppt_screenshots:
        if ss.slide_number == 23:
            img = ss.image_path
            break
    if not img:
        return "No screenshot of slide 23 found.", 0.0
    # Use VLM to check if the text 'Conclusion' is yellow
    prompt = "Is the text 'Conclusion' yellow? Reply 'yes' or 'no'."
    result = vlm_call(prompt, [img], temperature=0.0, max_tokens=10)
    if 'yes' in result.lower():
        return "The text 'Conclusion' is yellow.", 1.0
    return f"VLM response: {result}", 0.0

