def compute_score() -> tuple[str, float]:
    # We'll use VLM to compare screenshots of slide 23 before and after, except for the 'Conclusion:' text region.
    # Try to avoid VLM, but for general content change detection, it's the best option.
    orig = next((s for s in original_ppt_screenshots if s.slide_number == 23), None)
    mod = next((s for s in modified_ppt_screenshots if s.slide_number == 23), None)
    if not orig or not mod:
        return ("Missing slide 23 screenshots for visual comparison.", 0.0)
    prompt = (
        "Compare these two images of slide 23 in a PowerPoint presentation. The only acceptable difference "
        "should be that the text 'Conclusion:' changes from white to yellow. If you see any other differences, "
        "explain what they are. If the only difference is as described, say 'Only intended change'."
    )
    result = vlm_call(prompt, [orig.image_path, mod.image_path], temperature=0.0, max_tokens=128)
    if 'only intended change' in result.lower():
        return ("No unrelated content was changed on slide 23.", 1.0)
    return (f"Detected unrelated changes on slide 23: {result}", 0.0)
